INSERT INTO `sach` (`id`, `ma_sach`, `ten`, `tac_gia`, `the_loai_id`, `nha_xb`, `mo_ta`, `don_vi_tinh`, `hinh`, `so_luong`, `gia_nhap`, `ty_le_ln`, `hien_trang`, `da_nhap_hang`, `ngay_tao`) VALUES
(1, 'S0001', 'Mắt biếc', 'Nguyẽ̂n Nhật Ánh', 1, 'Tre', 'Popular teen romance fiction, by favorite author specializing in young readers stories, Nguyen Nhat Anh. 2019 edition. Considered one of his best work, this is a story of young love, growing up, and the sadness experience by young Ngan, when his high-school love does not love him back... This book had been translated into Japanese by Kato Sakae. A movie based on this book and directed by Victor Vu, is slotted to be premiered in December 24 2019.', 'cuốn', 'sach_S0001.jpg', 101, 50000.00, 23.00, 1, 1, '2026-03-14 17:32:28'),
(2, 'S0002', 'Thư mục quốc gia Việt Nam', 'Nhiều tác giả', 1, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0002.jpg', 100, 74000.00, 20.00, 1, 1, '2026-03-14 17:32:28'),
(3, 'S0003', 'Sương Khói Quê Nhà', 'Nguyễn Nhật Ánh', 1, 'Google Play eBooks', 'Những nhớ thương miền quê nghèo Quảng Nam qua kỷ niệm thời thơ bé; tình đời , tình người; tình thâm với bạn văn và những người mà anh yêu quý. Là những suy ngẫm của anh về cuộc đời, qua vô vàn chi tiết nhỏ trong phát hiện khiến đọc là thấy bất ngờ đầy thích thú. Hấp dẫn vô cùng là những bài có liên quan đến sách: từ tiệm sách, đến cuốn sách cụ thể, rồi người làm sách, chuyện sách ở Thụy Điển, Thái Lan… chuyện đi shopping, thời trang,đánh bạc, và tất nhiên chuyện bóng đá cũng được đề cập, vẫn bằng giọng hóm hỉnh vốn có.', 'cuốn', 'sach_S0003.jpg', 100, 64000.00, 33.00, 1, 1, '2026-03-14 17:32:28'),
(4, 'S0004', '你還不認識的新越南', 'Click-Vietnam 點點越南', 1, '讀書共和國╱真文化', '◎結合現代人文、習俗、工作、旅遊和生活的完整觀點 ◎超過200張照片，認識全新的、年輕的越南新社會 長居越南的兩位台灣朋友，帶大家看見新舊交融的越南現況。 ——秋姮╱John Hang TV—越南夯台灣創作者 真討厭啊，看完這本書又想去越南走走了。 ——藍白拖 旅行愛好者 臺灣和越南是二個往來非常緊密的國家，許多企業到越南投資，許多臺灣人外派到越南工作，也有很多越南配偶移民到臺灣，落地生根。然而，我們對於越南的認識，是否還停留在穿奧黛戴斗笠的美女、越戰留下的地道，以及越南河粉？ 越南經濟成長飛快，如今的越南已換上了一副年輕的新面貌。都市裡高樓林立，隨處都有現代特色的咖啡廳和手搖飲料店，方便通勤族的捷運、共享單車也越來越完整了，甚至一支越南開發的Zalo手機app，就能實現支付、轉帳、儲值、通訊、傳檔多種功能。 本書作者旅居越南多年，深切感受到越南近年來現代化的腳步加快了。以臺灣人的視角，作者在書中帶我們體會新越南的現代面貌、年輕族群生活，並整合當地重要的傳統習俗，搭配超過200張照片，讓你身歷其境感受到飛躍的社會氣氛。 無論你是想到越南工作、生活，或只是旅行，這本書帶你了解最新的越南社會，人還沒到越南就已經是個越南通了。', 'cuốn', 'sach_S0004.jpg', 100, 130000.00, 31.00, 1, 1, '2026-03-14 17:32:28'),
(5, 'S0005', 'Linh Ứng', 'Nguyễn Mạnh Tuấn', 1, 'First News', '“Linh ứng” là cuốn sách kể câu chuyện có thật về hành trình của gia đình nhà văn Nguyễn Mạnh Tuấn đi tìm hài cốt liệt sĩ Nguyễn Minh Khôi - người anh trai đã hy sinh trong cuộc chiến tranh khốc liệt, với những câu chuyện ly kỳ, bí ẩn đến mức nếu không được kể lại bởi người trong cuộc, hẳn chúng ta sẽ thấy hoài nghi. Theo tác giả, đây là cuốn sách tâm huyết nhất và cũng có thể là cuốn sách sau cùng trong sự nghiệp văn chương của ông, một câu chuyện riêng tư nhưng lại bao hàm biết bao câu chuyện chung khác. Đồng thời tác phẩm cũng cung cấp những tư liệu quý giá về những nhà ngoại cảm sở hữu năng lực nằm ngoài phạm vi lý giải của khoa học. Cuốn sách cũng là minh chứng cho việc dẫu thời gian có qua đi, vết thương chiến tranh vẫn còn đó, vẫn dày vò những người ở lại. Tìm kiếm người thân thất lạc sau chiến tranh vẫn luôn là câu chuyện day dứt của biết bao gia đình. Họ đi từ hy vọng đến thất vọng, rồi lại tìm kiếm hy vọng khác trên những chặng đường mới. “Có gia đình may mắn tìm được, có ngườ', 'cuốn', 'sach_S0005.jpg', 100, 124000.00, 30.00, 1, 1, '2026-03-14 17:32:28'),
(6, 'S0006', 'Decolonizing Comparative Literature', 'Chi P. Pham, Jose Monfred C. Sy', 1, 'Springer Nature', 'This book promotes a novel and nuanced understanding of how the practices of comparative literature have engaged with the politics of nation-building in postcolonial Southeast Asia. It provides readings of Southeast Asian literatures in a comparative context, demonstrating how such readings enable texts to engage with issues connected to postcolonial nation-building across the region. Such issues include social exclusion, urbanization and environmental destruction, post-war traumas, animal narratives, migration, identity, gender, and literature, and politics. In doing so, this book moves beyond traditional comparative literature which is overwhelmingly rooted in Western literature and scholarship. To this end, it extends an invitation to decolonize comparative literature as a discipline. Few studies have attempted to examine the alternative non-western literary traditions that emerge from this specific Asian region, and so this book presents a rich combination of theoretical and critic', 'cuốn', 'sach_S0006.jpg', 100, 133000.00, 29.00, 1, 1, '2026-03-14 17:32:28'),
(7, 'S0007', 'Chân dung thơ', 'Nhiều tác giả', 1, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0007.jpg', 100, 72000.00, 26.00, 1, 1, '2026-03-14 17:32:28'),
(8, 'S0008', '6 + 8', 'Nhiều tác giả', 1, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0008.jpg', 100, 71000.00, 32.00, 1, 1, '2026-03-14 17:32:28'),
(9, 'S0009', 'Thơ Việt Nam hiện đại', 'Nhiều tác giả', 1, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0009.jpg', 96, 103000.00, 21.00, 1, 1, '2026-03-14 17:32:28'),
(10, 'S0010', 'Paris Trong Hộp Giày', 'Mai Thanh Nga', 1, 'First News', 'Paris Trong Hộp Giày là tập truyện ngắn của tác giả Mai Thanh Nga được NXB Văn Học và Công ty First News – Trí Việt liên kết phát hành vừa ra mắt bạn đọc trong tháng 10 này. Tập truyện với 10 truyện ngắn và 1 truyện dài, đều là những câu chuyện được lấy bối cảnh Paris với nhân vật chính trong đó là những người Paris gốc Việt. Không như những tác phẩm văn học khác viết về người Việt sống tại Paris, nếu không tô hồng bởi màu sắc lung linh của “Kinh đô ánh sáng này” thì cũng nặng trĩu những mảnh đời xa xứ, Paris trong hộp giày của Mai Thanh Nga lại mang đến cho độc giả cảm giác hiện đại, tươi mới của đời sống người Việt ở thành phố hiện đại nhất châu Âu này. Có một không khí, tinh thần lãng đãng trong từng câu chuyện khiến tất cả những nhân vật người Việt trong tập truyện đều như là những con người châu Âu thuần túy, họ cũng có những vấn đề trong cuộc sống, những quan hệ tình cảm… như bao người bản xứ, có chăng khoác bên ngoài họ là người Việt, với tên Việt và định hình là người da vàng m', 'cuốn', 'sach_S0010.jpg', 100, 138000.00, 32.00, 1, 1, '2026-03-14 17:32:28'),
(11, 'S0011', 'Tạp chí cộng sản', 'Nhiều tác giả', 1, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0011.jpg', 100, 98000.00, 23.00, 1, 1, '2026-03-14 17:32:28'),
