(46, 'S0046', 'Từ điển giải thích thành ngữ tiếng Việt', 'Nhiều tác giả', 1, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0046.jpg', 100, 56000.00, 33.00, 1, 1, '2026-03-14 17:32:28'),
