(361, 'S0361', '45 năm khoa học và kỹ thuật Việt Nam, 1945-1990', 'Nhiều tác giả', 5, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0361.jpg', 100, 74000.00, 27.00, 1, 1, '2026-03-14 17:59:57'),
(362, 'S0362', 'Bầu trời chiều ẩn giấu', 'Châu Sa Nguyễn Phương Văn', 5, '5xu', 'Bầu trời chiều ẩn giấu là là một cuốn ebook rất nhỏ, chỉ có 7 chương, gói gọn trong 70 trang sách. Sách viết kiểu diễn nôm về các định luật vật lý quan trọng. Hình thức diễn đạt theo kiểu kể chuyện về hành trình và nỗ lực của con người đi khám phá thế giới tự nhiên. Thế giới tự nhiên ấy bắt đầu từ Big Bang cho đến ngày hôm nay, và ngày mai. Thế giới ấy có cả vũ trụ bao la, và cả những hạt hạ nguyên tử bé tí. Bốn chương đầu của cuốn sách nói về lịch sử hình thành khoa học tự nhiên và các phát minh quan trọng của vật lý, bắt đầu từ Thales của Hy lạp cổ đại, kết thúc bằng Edward Witten với M-Theory cuối thế kỷ 20. Phần này chỉ có 34 trang. Hai chương sau là về các sáng chế công nghệ để phục vụ cuộc sống và khám phá không gian. Phần 1 Chương 1: Từ Địa tâm đến Nhật tâm Chương 2: Từ Tất định đến bất định và hành trình đi tìm sự khởi đầu của vũ trụ Phần 2 Chương 3: Tiếng vọng từ Sáng Thế Chương 4: Bầu trời chiều ẩn giấu Chương 5: Bức xạ của Hawking Phần 3 Chương 6: Và đây là Elon Musk Chương ', 'cuốn', 'sach_S0362.jpg', 100, 145000.00, 22.00, 1, 1, '2026-03-14 17:59:57'),
(363, 'S0363', 'Ngữ nguyên tiếng Việt: 3000 từ vựng cơ bản', 'Trương Thái Du', 5, 'Trương Thái Du', 'Đúng ngày 1.7.2025, “sắp xếp lại giang sơn” để đất nước tiến vào kỷ nguyên mới, chúng tôi cũng hoàn thành công trình lớn của đời mình. Đó là phiên bản thứ ba của quyển “Ngữ nguyên tiếng Việt”. Tuy chỉ nghiệp dư, chúng tôi là người Việt Nam đầu tiên giải thích được trọn vẹn 18 từ vựng năm 1293 thời Trần; chỉ ra gốc rễ Hán Đường Mân của hàng ngàn âm “thuần Việt” mà xưa nay chưa ai biết: núi, non, sáu, bảy, lặn, lội… * Sai sót, nhầm lẫn là không tránh khỏi nhưng khi đã bác bỏ được học thuật thực dân, hậu thực dân phản động, chỉnh lý cho cả những tên tuổi trên bàn thờ ngữ học Việt Nam như Đào Duy Anh (*), Vương Lực… chúng tôi tin rằng quyển sách này đã đến gần sự thật nhất có thể. Nó xứng đáng được xem là thành tựu của một đời người sống không uổng phí. * Mời bạn đọc thử 30% nội dung trên các nền tảng điện tử như Google, Apple. Với những ai đã mua sách, xin vào lại giao dịch tải phiên bản cuối cùng. Xin chân thành cảm ơn độc giả! * (*) Khi giải mã 1/18 từ vựng thời Trần, Đào Duy Anh đã thê', 'cuốn', 'sach_S0363.jpg', 100, 102000.00, 27.00, 1, 1, '2026-03-14 17:59:57'),
(364, 'S0364', 'Chế độ thực dân Pháp trên đất Nam Kỳ (1859-1954)', 'Nguyễn Đình Tư, StreetLib', 5, 'NXB Tổng Hợp TP.HCM', 'Gần 100 năm cai trị vùng đất Nam Bộ, người Pháp đã gây ra bao tội ác đối với nhân dân ta. Nhưng ngày nay chế độ thực dân Pháp đã cáo chung hơn nửa thế kỷ, những gì Pháp làm tổn hại đến nhân dân ta đã đi vào dĩ vãng. Những lớp người sinh ra sau năm 1954 không còn thấy những cảnh người Pháp bắt nhốt hàng trăm chiến sĩ yêu nước của ta, đem ra tòa án xét xử, kết tội tử hình đem ra pháp trường xử bắn, hoặc kết án tù chung thân khổ sai, giam cầm đày đọa trong các nhà tù với những hình thức tra tấn cực kỳ dã man của thời trung cổ; không còn thấy những cảnh nhân dân nghèo khổ ở nông thôn và thành thị không đủ khả năng đóng sưu, đóng thuế, phải trốn chui trốn nhủi để tránh sự lùng bắt của bọn tuần đinh, mã tà; không còn thấy cảnh các tá điền bị chủ đồn điền bóc lột tận xương tận tủy, phải bán vợ đợ con cho bọn cường hào địa chủ; không còn thấy những cảnh cu li tại các đồn điền cao su bị bọn chủ thực dân Pháp sai bọn cặp rằng đánh đập, cưỡng bức lao động tận lực mà không cho ăn đầy đủ đến nỗi ph', 'cuốn', 'sach_S0364.jpg', 100, 63000.00, 23.00, 1, 1, '2026-03-14 17:59:57');
INSERT INTO `sach` (`id`, `ma_sach`, `ten`, `tac_gia`, `the_loai_id`, `nha_xb`, `mo_ta`, `don_vi_tinh`, `hinh`, `so_luong`, `gia_nhap`, `ty_le_ln`, `hien_trang`, `da_nhap_hang`, `ngay_tao`) VALUES
(365, 'S0365', 'KHẢO CHỨNG TIỀN SỬ VIỆT NAM', 'Trương Thái Du', 5, 'Trương Thái Du', 'Based on my researching of Chinese Classical Astronomy and Text, this book is the latter version of the former \"A New Approach on Old Issues Of Ancient Vietnamese History\" - ISBN 9781310245367. The new name is \"Researching of Vietnam Prehistory\", ISBN 9781370154548. By accessing and comparing vocabularies in the Sino-Tibetan and Austronesian languages, locating them in genetic maps with archaeological, cultural and bibliographic adjustments, we have figured out the meaning of important terms intimate to ancient Vietnamese history as presented below: 1. Việt 越 and Âu 歐 are homophones in the Han Dynasty and before, serving as transcriptions of Jiang - Zhe words by Chinese characters; originally and literally they mean water or water area, and their derivative sense is Country. They are similar to the word Quốc, which means earth/land/soil, and the derivative meaning of which is Country. Accordingly it can be inferred that Vietnam means Southern Country or Southern Land. 2. Lạc 駱 is equiv', 'cuốn', 'sach_S0365.jpg', 100, 136000.00, 35.00, 1, 1, '2026-03-14 17:59:57'),
