(372, 'S0372', 'Tié̂ng Việt phong phú', 'Bà̆ng Giang', 5, 'NXB Tổng hợp', 'Collection of quotations illustrating Vietnamese idioms and expressions.', 'cuốn', 'sach_S0372.jpg', 100, 110000.00, 28.00, 1, 1, '2026-03-14 17:59:58'),
(373, 'S0373', 'Tiếng Hàn tiêu chuẩn tập 1', 'Bộ giáo dục khoa học và kỹ thuật Hàn Quốc', 5, 'Hàn ngữ Kanata', 'Đây là cuốn sách phù hợp cho những ai muốn tự học tiếng Hàn theo cách chính thống Sách trình bày dễ hiểu. Song ngữ Hàn Việt nên rất tiện lợi cho những người tự học', 'cuốn', 'sach_S0373.jpg', 100, 106000.00, 21.00, 1, 1, '2026-03-14 17:59:58'),
(374, 'S0374', 'Tiếng Hàn tiêu chuẩn tập 2', 'Bộ giáo dục khoa học và kỹ thuật Hàn Quốc', 5, 'Hàn ngữ Kanata', 'Nối tiếp những bài học mở đầu của tập 1. Ở tập hai này, người học sẽ được học thêm những kiến thức ngữ pháp cơ bản nhất. Rất dễ dàng cho từng bước tự học', 'cuốn', 'sach_S0374.jpg', 100, 111000.00, 25.00, 1, 1, '2026-03-14 17:59:58'),
(375, 'S0375', 'Tiếng Hàn tiêu chuẩn tập 4', 'Bộ giáo dục khoa học và kỹ thuật Hàn Quốc', 5, 'Hàn ngữ Kanata', 'Tập hợp những kiến thức và từ vựng ở trình độ Trung Cấp. Sách được biên soạn dành riêng cho những người muốn tự học tiếng Hàn để sang Hàn Quốc sống', 'cuốn', 'sach_S0375.jpg', 100, 80000.00, 34.00, 1, 1, '2026-03-14 17:59:58'),
(376, 'S0376', 'Tiếng Hàn tiêu chuẩn tập 6', 'Bộ giáo dục khoa học và kỹ thuật Hàn Quốc', 5, 'Hàn ngữ Kanata', 'Đây là bộ sách hữu ích cho những ai học tiếng Hàn. Sách được phân theo sáu cấp độ tương ứng với 6 cuốn sách. Ở tập 6 này các bạn được học thêm một lượng từ vựng hữu ích trong giao tiếp hằng ngày.', 'cuốn', 'sach_S0376.jpg', 100, 51000.00, 32.00, 1, 1, '2026-03-14 17:59:58'),
(377, 'S0377', 'Tiếng Hàn tiêu chuẩn tập 3', 'Bộ giáo dục khoa học và kỹ thuật Hàn Quốc', 5, 'Hàn ngữ Kanata', 'Nối tiếp những kiến thức cơ bản của tập 2, những kiến thức được nâng cao hơn sẽ được trình bày ở tập 3. Đây là bộ sách được biên soạn dành riêng cho người Việt học tiếng Hàn', 'cuốn', 'sach_S0377.jpg', 100, 70000.00, 25.00, 1, 1, '2026-03-14 17:59:58'),
(378, 'S0378', 'Tiếng Hàn tiêu chuẩn tập 5', 'Bộ giáo dục khoa học và kỹ thuật Hàn Quốc', 5, 'Hàn ngữ Kanata', 'Đây là bộ sách hữu ích cho những ai học tiếng Hàn. Sách được phân theo sáu cấp độ tương ứng với 6 cuốn sách. Ở tập 5 này các bạn được học thêm một lượng từ vựng hữu ích trong giao tiếp hằng ngày.', 'cuốn', 'sach_S0378.jpg', 100, 59000.00, 34.00, 1, 1, '2026-03-14 17:59:58'),
