(380, 'S0380', 'Cuốn Chʾi Dẫn 1966', 'Học-viện quốc-gia hành-chánh (Vietnam)', 5, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0380.jpg', 100, 117000.00, 20.00, 1, 1, '2026-03-14 17:59:58'),
