(384, 'S0384', 'Quê hương', 'Nhiều tác giả', 5, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0384.jpg', 100, 112000.00, 33.00, 1, 1, '2026-03-14 17:59:58'),
(385, 'S0385', 'Văn kiện Đảng toàn tập', 'Đảng cộng sản Việt Nam', 5, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0385.jpg', 100, 89000.00, 27.00, 1, 1, '2026-03-14 17:59:58'),
(386, 'S0386', 'Chủ tịch và Chính phủ Hoa Kỳ bằng tiếng Việt', 'Nam H Nguyen', 5, 'Nam H Nguyen', 'Mục tiêu của Tổng thống Hoa Kỳ và Chính phủ là lấp đầy trí tuệ của bạn bằng kiến ​​thức lịch sử đơn giản và giúp mọi người quan tâm đến Lịch sử Hoa Kỳ và tìm hiểu về chính phủ của chúng ta. Mỗi vị Tổng thống của chúng tôi đã để lại dấu ấn của mình về lịch sử Hoa Kỳ, về cuộc sống của người Mỹ và mọi người trên thế giới. EBook rất dễ sử dụng, làm mới và được đảm bảo là thú vị và là một nguồn tài nguyên tuyệt vời để bắt đầu một số kiến ​​thức lịch sử của bạn với các Tổng thống, Các Nữ đầu tiên, Chi nhánh điều hành, Chi nhánh pháp lý, Chi nhánh Tư pháp, Hiến pháp và cộng Tạp chí Điều tra dân số năm 2010 cho thấy người châu Á là nhóm đua nhanh nhất, phong trào Quyền Công dân và mỗi bang có cờ. Chủ tịch Hoa Kỳ và Chính phủ sẽ giúp bạn bất cứ nơi nào bạn đi; nó là một công cụ tham khảo nhanh chóng và dễ dàng cho các trường tiểu học, trung học cơ sở, trung học, đại học, sinh viên tốt nghiệp và dân số nói chung mà bạn muốn kiểm tra! Chỉ cần nhớ một điều mà học tập không bao giờ dừng lại! Đọc đọ', 'cuốn', 'sach_S0386.jpg', 100, 64000.00, 33.00, 1, 1, '2026-03-14 17:59:58'),
(387, 'S0387', 'Sự phát triển của Thế giới Factbook 2018 bằng tiếng Việt', 'Nam H Nguyen', 5, 'Nam H Nguyen', 'Sự phát triển của Sách Thực tế Thế giới 2018 cung cấp thông tin về lịch sử, con người, đất đai, nước, xã hội, chính phủ, kinh tế, địa lý, bản đồ, cờ, truyền thông, vận tải, chính trị, dân số, lực lượng quốc phòng, quân sự và các vấn đề xuyên quốc gia cho 280 các thực thể trên thế giới. Đây là nguồn thông tin cần thiết cho sinh viên, du khách, nhà báo, trường học, quan chức chính phủ, nhà ngoại giao, học giả, chuyên gia và doanh nhân muốn có thêm thông tin về thế giới của họ trong lòng bàn tay của họ. Chỉ cần nhớ một điều mà học tập không bao giờ dừng lại! Đọc đọc đọc! Và viết, viết, viết! Một lời cảm ơn tới vợ tôi là Beth (Griffo) Nguyễn và những đứa con tuyệt vời của tôi, Taylor Nguyen và Ashton Nguyen, đã không có sự hỗ trợ tinh thần và sự giúp đỡ của họ, thì không thể có sách điện tử và âm thanh giáo dục nào cả. The Evolution of The World Fact book 2018 provides information on the history, people, land, water, society, government, economy, geography, maps, flags, communication, tran', 'cuốn', 'sach_S0387.jpg', 100, 113000.00, 24.00, 1, 1, '2026-03-14 17:59:58'),
(388, 'S0388', 'Từ điển từ và ý tiếng Việt', 'Đắc Quang Hồ', 5, 'NXB Tổng hợp', 'Vietnamese dictionary on synonyms.', 'cuốn', 'sach_S0388.jpg', 100, 91000.00, 23.00, 1, 1, '2026-03-14 17:59:58'),
(389, 'S0389', 'Lịch tài liệu', 'Nhiều tác giả', 5, 'NXB Tổng hợp', '', 'cuốn', 'sach_S0389.jpg', 100, 56000.00, 25.00, 1, 1, '2026-03-14 17:59:58'),
(390, 'S0390', 'Basic Korean For Beginner', 'Le Duy Khoa', 5, 'T-Book', 'Basic Korean For Beginner', 'cuốn', 'sach_S0390.jpg', 100, 128000.00, 28.00, 1, 1, '2026-03-14 17:59:58'),
(391, 'S0391', 'Từ điển Thiên văn học và Vật lý thiên văn', 'Đặng Vũ Tuấn Sơn', 5, 'VACA', 'Từ điển tra cứu toàn diện về thiên văn học bao gồm gần 2000 định nghĩa về: các qui ước và đơn vị trong thiên văn học; các thuật ngữ vật lý thiên văn; tên các hành tinh, vệ tinh, hành tinh lùn, sao chổi, tiểu hành tinh; các sao sáng nhất trên bầu trời đêm; các tinh vân và thiên hà nổi bật; các chòm sao trong thiên văn học hiện đại; các nhà thiên văn tiêu biểu; ... Sách đã được xuất bản lần đầu năm 2016 và tái bản vào năm 2018 và 2023 tại Việt Nam. Bản ebook này có bổ sung thuật ngữ và cập nhật thông tin về các phát hiện mới tính tới đầu năm 2023.', 'cuốn', 'sach_S0391.jpg', 100, 146000.00, 25.00, 1, 1, '2026-03-14 17:59:58'),
