(415, 'S0415', 'Từ điẻ̂n chữ vié̂t tá̆t thông dụng Việt-Anh-Pháp', 'Nhân Đàm Lê', 5, 'NXB Tổng hợp', 'Giới thiệu các chữ viết tắt thông dụng bằng tiếng Việt - tiếng Anh - tiếng Pháp, được sắp xếp theo thứ tự chữ cái.', 'cuốn', 'sach_S0415.jpg', 100, 130000.00, 32.00, 1, 1, '2026-03-14 17:59:58'),
